class Solution:
    def numPrimeArrangements(self, n):
        MOD = 10**9 + 7
        def is_prime(x):
            if x < 2:
                return False
            i = 2
            while i * i <= x:
                if x % i == 0:
                    return False
                i += 1
            return True
        primes = sum(1 for x in range(2, n + 1) if is_prime(x))
        from math import factorial
        return (factorial(primes) * factorial(n - primes)) % MOD

