class Solution:
    def numPrimeArrangements(self, n):
        MOD = 10**9 + 7
        sieve = [True] * (n + 1)
        if n >= 0:
            sieve[0] = False
        if n >= 1:
            sieve[1] = False
        for i in range(2, int(n**0.5) + 1):
            if sieve[i]:
                for j in range(i * i, n + 1, i):
                    sieve[j] = False
        p = sum(1 for i in range(2, n + 1) if sieve[i])
        def fact(m):
            r = 1
            for k in range(2, m + 1):
                r = (r * k) % MOD
            return r
        return (fact(p) * fact(n - p)) % MOD

